//refAssemblies: TCAdmin.SDK.dll, TCAdmin.GameHosting.SDK.dll, TCAdmin.Scripting.dll, TCAdmin.Monitor.dll
using System;
using System.Collections.Generic;
using System.Linq;
using TCAdmin.SDK.DynamicInput.Controls;
using TCAdmin.Web.Shared.Models.DynamicInput;

var Globals = new TCAdmin.Scripting.Engines.Addons.CSharpGlobals(); // DO NOT MODIFY THIS LINE

var console = Globals.ScriptConsole;

var msgResult = await Globals.ThisScript.ShowMessageBox("Question", "Should I ask for values using a dialog?", yesText: "Yes", noText: "No", cancelText: "Cancel");

if(msgResult == null)
{
    Globals.ThisScript.Alert("😔 Canceled", "Canceled by user!");
    return;
}

console.WriteLine("Asking for values...");

var item1 = new DynamicTextBox
{
    Id = "1",
    Label = "Enter first value",
    Description = "I'm going to do something with this value",
    DefaultValue = "",
    Required = false
};

var item2 = new DynamicTextBox
{
    Id = "2",
    Label = "Enter second value",
    Description = "This value is optional",
    DefaultValue = "I set a default value",
    Required = false
};

var item3 = new DynamicSwitch
{
    Id = "3",
    Label = "Uncheck this",
    DefaultValue = false,
    Required = false,
    CheckedValue = "On",
    UncheckedValue = "Off"
};

var item4 = new DynamicCheckBox
{
    Id = "4",
    Label = "Child value (only visible if parent is checked)",
    DefaultValue = false,
    Required = false,
    CheckedValue = "On",
    UncheckedValue = "Off",
    ParentId = "3",
    ParentValue = "On"
};

var item5 = new DynamicNumericTextBox
{
    Id = "5",
    Label = "Enter a numeric value",
    Description = "This value is required",
    DefaultValue = null,
    Required = true
};

var item6 = new DynamicComboBox
{
    Id = "6",
    Label = "Select from the list",
    Description = "This value is required",
    DefaultValue = null,
    Required = true
};

item6.Items.Add(new DynamicComboBoxItem { Text = "Value 1", Value = "1" });
item6.Items.Add(new DynamicComboBoxItem { Text = "Value 2", Value = "2" });

var inputConfig = new InputConfiguration() { IsDialog = msgResult.Value, AllowCancel = true };
var result = await Globals.ThisScript.Input(inputConfig, item1, item2, item3, item4, item5, item6);

if(result.Canceled)
{
    await Globals.ThisScript.Alert("😔 Canceled", "Canceled by user!");
} else {
    console.WriteLine("------------------------------------------------------------------------------");
    console.WriteLine($"Value 1: {result.Values["1"]}");
    console.WriteLine($"Value 2: {result.Values["2"]}");
    console.WriteLine($"Value 3: {result.Values["3"]}");
    console.WriteLine($"Value 4: {result.Values["4"]}");
    console.WriteLine($"Value 5: {result.Values["5"]}");
    console.WriteLine($"Value 6: {result.Values["6"]}");
    console.WriteLine("------------------------------------------------------------------------------");
    await Globals.ThisScript.Alert("Sucess", $"The {result.Values.Count} values were captured successfully!");
    // ReturnValue = $"First: {result["1"]} Second: {result["2"]}";
}

