//refAssemblies: TCAdmin.SDK.dll, TCAdmin.GameHosting.SDK.dll, TCAdmin.Scripting.dll, TCAdmin.Monitor.dll
using System;
using System.IO;

var Globals = new TCAdmin.Scripting.Engines.Addons.CSharpGlobals(); // DO NOT MODIFY THIS LINE

Globals.ScriptConsole.WriteLine("This script will fail if \"Run Impersonated\" is checked");

DirectoryInfo dir;

if(Environment.OSVersion.Platform == PlatformID.Unix) {
  dir = new System.IO.DirectoryInfo("/root");
  if(dir.Exists) {
    Globals.ScriptConsole.WriteLine("Printing contents of {0}:", dir.FullName);
    foreach(var file in dir.GetFiles()) {
      Globals.ScriptConsole.WriteLine(file.Name);
    }
  }
}
else {
  var username = System.Security.Principal.WindowsIdentity.GetCurrent().Name;
  Globals.ScriptConsole.WriteLine($"Running script as {username}");
  dir = new System.IO.DirectoryInfo("C:\\Program Files\\DeleteMe");
  Globals.ScriptConsole.WriteLine("Creating the path {0}", dir.FullName);
  dir.Create();
  Globals.ScriptConsole.WriteLine("Deleting the path {0}", dir.FullName);
  dir.Delete();
}

